import { useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { Loader2, Building2, RefreshCw, ImageIcon } from "lucide-react";

export default function AdminMichelinPhotos() {
  const { t } = useTranslation();
  const [country, setCountry] = useState<string>("");
  const [city, setCity] = useState<string>("");
  const [batchSize, setBatchSize] = useState<number>(20);
  const [force, setForce] = useState<boolean>(false);
  const [running, setRunning] = useState(false);
  const [lastResult, setLastResult] = useState<any>(null);

  // Country distribution for Michelin restaurants
  const { data: countries = [], isLoading } = useQuery({
    queryKey: ["michelin-countries"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("country, image_url")
        .not("michelin_stars", "is", null)
        .eq("visible", true);
      if (error) throw error;
      const map = new Map<string, { total: number; missing: number }>();
      (data || []).forEach((r: any) => {
        if (!r.country) return;
        const cur = map.get(r.country) || { total: 0, missing: 0 };
        cur.total += 1;
        if (!r.image_url) cur.missing += 1;
        map.set(r.country, cur);
      });
      return Array.from(map.entries())
        .map(([name, v]) => ({ name, ...v }))
        .sort((a, b) => b.total - a.total);
    },
  });

  const selected = useMemo(() => countries.find((c) => c.name === country), [country, countries]);

  const handleRun = async () => {
    if (!country && !city) {
      toast.error(t("admin.michelinPhotos.pickCountry", "请选择国家或填写城市"));
      return;
    }
    setRunning(true);
    setLastResult(null);
    try {
      const { data, error } = await supabase.functions.invoke("refresh-michelin-building-photos", {
        body: { country: country || undefined, city: city || undefined, batch_size: batchSize, force },
      });
      if (error) throw error;
      setLastResult(data);
      toast.success(
        t("admin.michelinPhotos.updated", "已更新 {{n}} 家（跳过 {{s}}）", {
          n: data?.updated ?? 0,
          s: data?.skipped ?? 0,
        }),
      );
    } catch (e: any) {
      toast.error(e?.message || t("common.error", "出错了"));
    } finally {
      setRunning(false);
    }
  };

  return (
    <div className="container mx-auto p-6 max-w-3xl">
      <div className="mb-6">
        <h1 className="text-2xl font-bold flex items-center gap-2">
          <Building2 className="w-6 h-6 text-primary" />
          {t("admin.michelinPhotos.title", "米其林卡片建筑外观照片")}
        </h1>
        <p className="text-sm text-muted-foreground mt-1">
          {t(
            "admin.michelinPhotos.subtitle",
            "用 Google 街景门面直出替换米其林餐厅卡片封面，第一眼就是熟悉的真实门脸。",
          )}
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-base">{t("admin.michelinPhotos.scope", "处理范围")}</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div>
            <Label>{t("admin.michelinPhotos.country", "国家")}</Label>
            <Select value={country} onValueChange={setCountry} disabled={isLoading}>
              <SelectTrigger className="mt-1.5">
                <SelectValue placeholder={t("admin.michelinPhotos.pickCountry", "请选择国家")} />
              </SelectTrigger>
              <SelectContent>
                {countries.map((c) => (
                  <SelectItem key={c.name} value={c.name}>
                    {c.name} · {c.total} ({t("admin.michelinPhotos.missing", "缺图")} {c.missing})
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label>{t("admin.michelinPhotos.cityOptional", "城市（可选，覆盖国家）")}</Label>
            <Input
              className="mt-1.5"
              value={city}
              onChange={(e) => setCity(e.target.value)}
              placeholder="Paris / Lisbon / Singapore"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>{t("admin.michelinPhotos.batch", "本次处理数量")}</Label>
              <Input
                type="number"
                min={1}
                max={50}
                className="mt-1.5"
                value={batchSize}
                onChange={(e) => setBatchSize(Math.max(1, Math.min(50, Number(e.target.value) || 1)))}
              />
              <p className="text-[11px] text-muted-foreground mt-1">
                {t("admin.michelinPhotos.batchHint", "建议 ≤ 30，避免限速")}
              </p>
            </div>
            <div className="flex items-end gap-3 pb-1">
              <div className="flex items-center gap-2">
                <Switch id="force" checked={force} onCheckedChange={setForce} />
                <Label htmlFor="force" className="cursor-pointer">
                  {t("admin.michelinPhotos.force", "强制覆盖现有照片")}
                </Label>
              </div>
            </div>
          </div>

          {selected && (
            <div className="rounded-md bg-muted/40 p-3 text-sm">
              <div className="flex items-center gap-2">
                <Badge variant="secondary">{selected.name}</Badge>
                <span>
                  {t("admin.michelinPhotos.totalLabel", "总数")}: <b>{selected.total}</b>
                </span>
                <span>
                  · {t("admin.michelinPhotos.missing", "缺图")}: <b>{selected.missing}</b>
                </span>
              </div>
            </div>
          )}

          <Button onClick={handleRun} disabled={running} className="w-full">
            {running ? (
              <>
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                {t("admin.michelinPhotos.running", "处理中…")}
              </>
            ) : (
              <>
                <RefreshCw className="w-4 h-4 mr-2" />
                {t("admin.michelinPhotos.runBtn", "开始替换为建筑外观")}
              </>
            )}
          </Button>

          {lastResult && (
            <div className="rounded-md border p-3 text-sm space-y-1">
              <div className="flex items-center gap-2 font-medium">
                <ImageIcon className="w-4 h-4 text-primary" />
                {t("admin.michelinPhotos.lastBatch", "本次批次")}
              </div>
              <div>
                {t("admin.michelinPhotos.updatedLine", "已更新: {{n}} 家", { n: lastResult.updated ?? 0 })}
              </div>
              <div className="text-muted-foreground">
                {t("admin.michelinPhotos.fallbackLine", "无街景，已转交 Places 兜底: {{n}} 家", {
                  n: lastResult.fallback_triggered ?? 0,
                })}
              </div>
              {(lastResult.coords_corrected ?? 0) > 0 && (
                <div className="text-muted-foreground">
                  {t("admin.michelinPhotos.coordsCorrectedLine", "坐标已校正: {{n}} 家", {
                    n: lastResult.coords_corrected,
                  })}
                </div>
              )}
              <div className="text-muted-foreground">
                {t("admin.michelinPhotos.skippedLine", "跳过(缺坐标或写库失败): {{n}} 家", { n: lastResult.skipped ?? 0 })}
              </div>
              <div className="text-muted-foreground">
                {t("admin.michelinPhotos.remaining", "剩余约 {{n}} 家", { n: lastResult.remaining ?? 0 })}
              </div>
              <p className="text-xs text-muted-foreground">
                {t(
                  "admin.michelinPhotos.refreshNote",
                  "封面已即时写入数据库，刷新前台即可看到新的门面照片。",
                )}
              </p>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
